class Solution:
    def minCost(self, colors, neededTime):
        colors = list(colors)
        times = list(neededTime)
        total = 0
        changed = True
        while changed:
            changed = False
            i = 0
            while i < len(colors) - 1:
                if colors[i] == colors[i + 1]:
                    if times[i] <= times[i + 1]:
                        total += times[i]
                        del colors[i]
                        del times[i]
                    else:
                        total += times[i + 1]
                        del colors[i + 1]
                        del times[i + 1]
                    changed = True
                else:
                    i += 1
        return total

