var minCost = function(colors, neededTime) {
    const n = colors.length;
    let total = 0;
    let i = 0;
    while (i < n) {
        let j = i;
        let groupSum = 0;
        let groupMax = 0;
        while (j < n && colors[j] === colors[i]) {
            groupSum += neededTime[j];
            if (neededTime[j] > groupMax) groupMax = neededTime[j];
            j++;
        }
        total += groupSum - groupMax;
        i = j;
    }
    return total;
};
